131	// RunFunc executes a single agent invocation and returns the Result. Used by
132	// the comparison helpers so the same orchestration logic can be driven by
133	// either the legacy Runner or the agent service.
134	type RunFunc func(opts RunOptions) (*Result, error)
135	
136	// RunCompareWith dispatches the same prompt to multiple harnesses, executing
137	// each arm via run, and returns a ComparisonRecord. Production callers should
138	// use RunCompareViaService; tests may pass Runner.Run as the closure.
139	func RunCompareWith(run RunFunc, opts CompareOptions, resolvePrompt func(RunOptions) (string, error), cleanupSandbox func(repoDir, compareID string)) (*ComparisonRecord, error) {
140		if len(opts.Harnesses) == 0 {
141			return nil, fmt.Errorf("agent: compare requires at least one harness")
142		}
143		if resolvePrompt == nil {
144			resolvePrompt = defaultResolvePromptForCompare
145		}
146	
147		prompt, err := resolvePrompt(opts.RunOptions)
148		if err != nil {
149			return nil, err
150		}
151	
152		id := genCompareID()
153		record := &ComparisonRecord{
154			ID:        id,
155			Timestamp: time.Now().UTC(),
156			Prompt:    prompt,
157			Arms:      make([]ComparisonArm, len(opts.Harnesses)),
158		}
159	
160		baseDir := opts.WorkDir
161		if baseDir == "" {
162			baseDir, _ = os.Getwd()
163		}
164	
165		worktrees := make([]string, len(opts.Harnesses))
166		if opts.Sandbox {
167			for i, harness := range opts.Harnesses {
168				label := harness
169				if l, ok := opts.ArmLabels[i]; ok {
170					label = l
171				}
172				wt, err := createCompareWorktree(baseDir, id, label)
173				if err != nil {
174					record.Arms[i] = ComparisonArm{
175						Harness:  label,
176						ExitCode: 1,
177						Error:    fmt.Sprintf("worktree: %s", err),
178					}
179					continue
180				}
181				worktrees[i] = wt
182			}
183		}
184	
185		var wg sync.WaitGroup
186		for i, harness := range opts.Harnesses {
187			if opts.Sandbox && worktrees[i] == "" && record.Arms[i].Error != "" {
188				continue
189			}
190			wg.Add(1)
191			go func(idx int, harnessName string) {
192				defer wg.Done()
193				record.Arms[idx] = runCompareArmWith(run, opts, idx, harnessName, baseDir, prompt, worktrees[idx])
194			}(i, harness)
195		}
196		wg.Wait()
197	
198		if opts.Sandbox && !opts.KeepSandbox {
199			if cleanupSandbox != nil {
200				cleanupSandbox(baseDir, id)
201			} else {
202				cleanupCompareWorktrees(baseDir, id)
203			}
204		}
205	
206		return record, nil
207	}
