440	// RunQuorumWith invokes multiple harnesses concurrently and returns each
441	// result. Production callers should use RunQuorumViaService; tests may pass
442	// Runner.Run.
443	func RunQuorumWith(run RunFunc, opts QuorumOptions) ([]*Result, error) {
444		if len(opts.Harnesses) == 0 {
445			return nil, fmt.Errorf("agent: quorum requires at least one harness")
446		}
447	
448		threshold := effectiveThreshold(opts.Strategy, opts.Threshold, len(opts.Harnesses))
449		if threshold < 1 || threshold > len(opts.Harnesses) {
450			return nil, fmt.Errorf("agent: invalid quorum threshold %d for %d harnesses", threshold, len(opts.Harnesses))
451		}
452	
453		results := make([]*Result, len(opts.Harnesses))
454		var wg sync.WaitGroup
455		var mu sync.Mutex
456		var firstErr error
457	
458		for i, name := range opts.Harnesses {
459			wg.Add(1)
460			go func(idx int, harness string) {
461				defer wg.Done()
462				runOpts := opts.RunOptions
463				runOpts.Harness = harness
464				result, err := run(runOpts)
465				mu.Lock()
466				if err != nil && firstErr == nil {
467					firstErr = err
468				}
469				results[idx] = result
470				mu.Unlock()
471			}(i, name)
472		}
473		wg.Wait()
474	
475		return results, firstErr
476	}
